import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { contentApi } from '../../services/api';
import ContentTable from '../../components/admin/ContentTable';
import '../Admin.css';

export default function AdminBlogs() {
  const [blogs, setBlogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState('');

  const loadBlogs = () => {
    contentApi
      .getAll({ type: 'blog' })
      .then(setBlogs)
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    loadBlogs();
  }, []);

  const showMessage = (text) => {
    setMessage(text);
    setTimeout(() => setMessage(''), 3000);
  };

  const handleToggle = async (id, field) => {
    try {
      const updated = await contentApi.toggle(id, field);
      setBlogs((prev) => prev.map((b) => (b.id === id ? updated : b)));
      showMessage(`${field} updated for "${updated.title}"`);
    } catch (err) {
      showMessage(err.message);
    }
  };

  const handleDelete = async (id, title) => {
    if (!window.confirm(`Delete blog "${title}"?`)) return;
    try {
      await contentApi.delete(id);
      setBlogs((prev) => prev.filter((b) => b.id !== id));
      showMessage('Blog deleted');
    } catch (err) {
      showMessage(err.message);
    }
  };

  return (
    <div className="dash-page">
      <div className="dash-page__header">
        <div>
          <h1>Blogs</h1>
          <p>Manage all blog posts — toggle featured & trending status</p>
        </div>
        <Link to="/admin/blogs/upload" className="btn btn-primary">
          + Upload Blog
        </Link>
      </div>

      {message && <div className="dash-toast">{message}</div>}

      {loading ? (
        <div className="page-loading">Loading blogs...</div>
      ) : (
        <ContentTable
          items={blogs}
          onToggle={handleToggle}
          onDelete={handleDelete}
          emptyMessage="No blogs yet. Publish your first blog."
        />
      )}
    </div>
  );
}
